41:      * @deprecated Since 4.0. Use {@link #ConsumerRecords(Map, Map)} instead.
42:      */
43:     @Deprecated
44:     public ConsumerRecords(Map<TopicPartition, List<ConsumerRecord<K, V>>> records) {
45:         this(records, Map.of());
46:     }
47: 
48:     public ConsumerRecords(Map<TopicPartition, List<ConsumerRecord<K, V>>> records, final Map<TopicPartition, OffsetAndMetadata> nextOffsets) {
49:         this.records = records;
50:         this.nextOffsets = Map.copyOf(nextOffsets);
51:     }
52: 
53:     /**
54:      * Get just the records for the given partition
55:      * 
56:      * @param partition The partition to get records for
57:      */
58:     public List<ConsumerRecord<K, V>> records(TopicPartition partition) {
59:         List<ConsumerRecord<K, V>> recs = this.records.get(partition);
60:         if (recs == null)
61:             return Collections.emptyList();
62:         else
63:             return Collections.unmodifiableList(recs);
64:     }
65: 
66:     /**
67:      * Get the next offsets and metadata corresponding to all topic partitions for which the position have been advanced in this poll call
68:      * @return the next offsets that the consumer will consume
69:      */
70:     public Map<TopicPartition, OffsetAndMetadata> nextOffsets() {
71:         return nextOffsets;
72:     }
73: 
74:     /**
75:      * Get just the records for the given topic
76:      */
77:     public Iterable<ConsumerRecord<K, V>> records(String topic) {
78:         if (topic == null)
79:             throw new IllegalArgumentException("Topic must be non-null.");
80:         List<List<ConsumerRecord<K, V>>> recs = new ArrayList<>();
81:         for (Map.Entry<TopicPartition, List<ConsumerRecord<K, V>>> entry : records.entrySet()) {
82:             if (entry.getKey().topic().equals(topic))
83:                 recs.add(entry.getValue());
84:         }
85:         return new ConcatenatedIterable<>(recs);
86:     }
87: 
88:     /**
89:      * Get the partitions which have records contained in this record set.
90:      * @return the set of partitions with data in this record set (may be empty if no data was returned)
91:      */
92:     public Set<TopicPartition> partitions() {
93:         return Collections.unmodifiableSet(records.keySet());
94:     }
95: 
96:     @Override
97:     public Iterator<ConsumerRecord<K, V>> iterator() {
98:         return new ConcatenatedIterable<>(records.values()).iterator();
99:     }
100: 
101:     /**
102:      * The number of records for all topics
103:      */
104:     public int count() {
105:         int count = 0;
106:         for (List<ConsumerRecord<K, V>> recs: this.records.values())
107:             count += recs.size();
108:         return count;
109:     }
110: 
111:     private static class ConcatenatedIterable<K, V> implements Iterable<ConsumerRecord<K, V>> {
112: 
113:         private final Iterable<? extends Iterable<ConsumerRecord<K, V>>> iterables;
114: 
115:         public ConcatenatedIterable(Iterable<? extends Iterable<ConsumerRecord<K, V>>> iterables) {
116:             this.iterables = iterables;
117:         }
118: 
119:         @Override
120:         public Iterator<ConsumerRecord<K, V>> iterator() {
121:             return new AbstractIterator<>() {
122:                 final Iterator<? extends Iterable<ConsumerRecord<K, V>>> iters = iterables.iterator();
123:                 Iterator<ConsumerRecord<K, V>> current;
124: 
125:                 protected ConsumerRecord<K, V> makeNext() {
126:                     while (current == null || !current.hasNext()) {
127:                         if (iters.hasNext())
128:                             current = iters.next().iterator();
129:                         else
130:                             return allDone();
131:                     }
132:                     return current.next();
133:                 }
134:             };
135:         }
136:     }
137: 
138:     public boolean isEmpty() {
139:         return records.isEmpty();
140:     }
141: 
142:     @SuppressWarnings("unchecked")
143:     public static <K, V> ConsumerRecords<K, V> empty() {
144:         return (ConsumerRecords<K, V>) EMPTY;
145:     }
146: 
147: }
