### Rebalance Listener with State Management

```java
public class StatefulConsumer {
    static class SaveOffsetsOnRebalance implements ConsumerRebalanceListener {
        private KafkaConsumer<String, String> consumer;
        private OffsetStore offsetStore;

        SaveOffsetsOnRebalance(KafkaConsumer<String, String> consumer,
                              OffsetStore offsetStore) {
            this.consumer = consumer;
            this.offsetStore = offsetStore;
        }

        @Override
        public void onPartitionsRevoked(Collection<TopicPartition> partitions) {
            // Save offsets before losing partitions
            Map<TopicPartition, OffsetAndMetadata> offsetsToCommit = new HashMap<>();
            for (TopicPartition tp : partitions) {
                offsetsToCommit.put(tp, new OffsetAndMetadata(
                    consumer.position(tp),
                    "Saved at " + System.currentTimeMillis()
                ));
            }

            try {
                consumer.commitSync(offsetsToCommit);
                System.out.println("Saved offsets for " + partitions);
            } catch (CommitFailedException e) {
                System.err.println("Failed to save offsets: " + e);
            }
        }

        @Override
        public void onPartitionsAssigned(Collection<TopicPartition> partitions) {
            // Restore offsets when gaining partitions
            for (TopicPartition tp : partitions) {
                OffsetAndMetadata offsetMeta = offsetStore.fetch(tp);
                if (offsetMeta != null) {
                    consumer.seek(tp, offsetMeta);
                    System.out.println("Restored " + tp + " to " + offsetMeta.offset());
                } else {
                    consumer.seekToBeginning(Collections.singleton(tp));
                    System.out.println("No saved offset for " + tp + ", starting from beginning");
                }
            }
        }
    }

    public static void main(String[] args) {
        Properties props = new Properties();
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ConsumerConfig.GROUP_ID_CONFIG, "my-group");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, "false");

        KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props);
        OffsetStore offsetStore = new MyOffsetStore();  // Custom implementation

        consumer.subscribe(
            Collections.singleton("orders"),
            new SaveOffsetsOnRebalance(consumer, offsetStore)
        );

        try {
            while (true) {
                ConsumerRecords<String, String> records = consumer.poll(Duration.ofSeconds(1));
                for (ConsumerRecord<String, String> record : records) {
                    processOrder(record);
                }
            }
        } finally {
            consumer.close();
        }
    }

    static void processOrder(ConsumerRecord<String, String> record) {
        System.out.println("Processing: " + record.value());
    }
}

interface OffsetStore {
    OffsetAndMetadata fetch(TopicPartition tp);
    void save(TopicPartition tp, OffsetAndMetadata offset);
}

class MyOffsetStore implements OffsetStore {
    private Map<TopicPartition, OffsetAndMetadata> offsets = new HashMap<>();

    @Override
    public OffsetAndMetadata fetch(TopicPartition tp) {
        return offsets.get(tp);
    }

    @Override
    public void save(TopicPartition tp, OffsetAndMetadata offset) {
        offsets.put(tp, offset);
    }
}
```

